const testData = {
  body: {
    sessionId: "74a21f4d-38e5-47dc-b910-393ee031008d"
  }
};
return [{ json: testData }];

const body = $input.first().json.body || $input.first().json || {};
const sessionId = body.sessionId || body.session_id;

if (!sessionId) {
  throw new Error('Session ID is required');
}

console.log('=== LEVERAGE CALCULATION V2.3 START ===');
console.log('Session ID:', sessionId);

return [{ json: { sessionId } }];

// ============================================================================
// CLARENCE LEVERAGE CALCULATION ALGORITHM V2.3
// Now handles missing customer_requirements via fallback data
// ============================================================================

const sessionId = $('Extract Session ID').first().json.sessionId;
const customerReq = $('Fetch Customer Requirements').first().json || {};
const providerCap = $('Fetch Provider Capabilities').first().json || {};
const providerBid = $('Fetch Provider Bid & Questionnaire').first().json || {};

console.log('=== CALCULATING LEVERAGE V2.3 ===');
console.log('Data Source:', customerReq.data_source || 'unknown');
console.log('Customer Company:', customerReq.company_name);
console.log('Provider Company:', providerCap.company_name || providerBid.provider_company);

// Parse questionnaire data
let customerQuestionnaire = {};
let providerQuestionnaire = {};

try {
  if (customerReq.questionnaire_data) {
    customerQuestionnaire = typeof customerReq.questionnaire_data === 'string' 
      ? JSON.parse(customerReq.questionnaire_data) 
      : customerReq.questionnaire_data;
  }
  if (customerReq.strategic_answers) {
    const strategic = typeof customerReq.strategic_answers === 'string'
      ? JSON.parse(customerReq.strategic_answers)
      : customerReq.strategic_answers;
    customerQuestionnaire = { ...customerQuestionnaire, ...strategic };
  }
} catch (e) { console.log('Could not parse customer questionnaire:', e.message); }

try {
  if (providerBid.questionnaire_data) {
    providerQuestionnaire = typeof providerBid.questionnaire_data === 'string' 
      ? JSON.parse(providerBid.questionnaire_data) 
      : providerBid.questionnaire_data;
  }
} catch (e) { console.log('Could not parse provider questionnaire:', e.message); }

// ============================================================================
// LEVERAGE FACTOR CALCULATIONS (4 factors, 25% each)
// ============================================================================

function calculateMarketDynamics() {
  let score = 50;
  let rationale = [];

  let numBidders = 3;
  const biddersStr = String(customerReq.number_of_bidders || '3');
  if (biddersStr.includes('-')) {
    const parts = biddersStr.split('-');
    numBidders = (parseInt(parts[0]) + parseInt(parts[1])) / 2;
  } else {
    numBidders = parseInt(biddersStr) || 3;
  }

  if (numBidders >= 5) { score += 15; rationale.push('Multiple providers competing (' + numBidders + ')'); }
  else if (numBidders >= 3) { score += 10; rationale.push('Healthy provider competition (' + numBidders + ')'); }
  else if (numBidders < 2) { score -= 10; rationale.push('Limited provider options'); }

  const marketPosition = String(customerReq.market_position || 'moderate').toLowerCase();
  if (marketPosition === 'strong') { score += 10; rationale.push('Strong market position'); }
  else if (marketPosition === 'weak') { score -= 10; rationale.push('Weak market position'); }

  const decisionTimeline = String(customerReq.decision_timeline || 'normal').toLowerCase();
  if (decisionTimeline === 'urgent') { score -= 15; rationale.push('Urgent timeline pressure'); }
  else if (decisionTimeline === 'flexible') { score += 10; rationale.push('Flexible timeline'); }

  return { score: Math.max(20, Math.min(80, score)), rationale: rationale.join('. ') || 'Standard market conditions' };
}

function calculateEconomicFactors() {
  let score = 50;
  let rationale = [];

  const dealValue = parseFloat(customerReq.deal_value) || 500000;

  let customerRevenue = 50000000;
  const revenueStr = String(customerReq.annual_revenue || '50M');
  if (revenueStr.includes('M')) {
    const match = revenueStr.match(/(\d+)M/);
    if (match) customerRevenue = parseInt(match[1]) * 1000000;
  }

  const dealToRevenue = (dealValue / customerRevenue) * 100;

  if (dealToRevenue < 2) { score += 15; rationale.push('Small deal relative to customer size (' + dealToRevenue.toFixed(1) + '%)'); }
  else if (dealToRevenue > 5) { score -= 10; rationale.push('Significant investment (' + dealToRevenue.toFixed(1) + '% of revenue)'); }

  const switchingCosts = String(customerReq.switching_costs || 'moderate').toLowerCase();
  if (switchingCosts === 'low' || switchingCosts === 'minimal') { score += 10; rationale.push('Low switching costs'); }
  else if (switchingCosts === 'high' || switchingCosts === 'significant') { score -= 15; rationale.push('High switching costs'); }

  const budgetFlex = String(customerReq.budget_flexibility || 'moderate').toLowerCase();
  if (budgetFlex === 'high' || budgetFlex === 'flexible') { score += 10; rationale.push('Flexible budget'); }
  else if (budgetFlex === 'low' || budgetFlex === 'fixed') { score -= 10; rationale.push('Fixed budget constraints'); }

  return { score: Math.max(20, Math.min(80, score)), rationale: rationale.join('. ') || 'Standard economic position' };
}

function calculateStrategicPosition() {
  let score = 50;
  let rationale = [];

  const criticality = String(customerReq.service_criticality || 'important').toLowerCase();
  if (criticality === 'critical' || criticality === 'essential') { score -= 15; rationale.push('Business-critical service'); }
  else if (criticality === 'low' || criticality === 'nice-to-have') { score += 15; rationale.push('Non-critical service'); }

  const incumbentStatus = String(customerReq.incumbent_status || '').toLowerCase();
  if (incumbentStatus.includes('replacing')) { score += 10; rationale.push('Replacing incumbent provider'); }

  const alternativeOptions = String(customerReq.alternative_options || '').toLowerCase();
  if (alternativeOptions.includes('strong')) { score += 10; rationale.push('Strong alternatives available'); }
  else if (alternativeOptions.includes('limited') || alternativeOptions.includes('weak')) { score -= 10; rationale.push('Limited alternatives'); }

  return { score: Math.max(20, Math.min(80, score)), rationale: rationale.join('. ') || 'Balanced strategic position' };
}

function calculateBATNA() {
  let score = 50;
  let rationale = [];

  const walkAway = String(customerReq.walk_away_point || '').toLowerCase();
  if (walkAway.includes('delay') || walkAway.includes('walk')) { score += 15; rationale.push('Customer can walk away or delay'); }
  else if (walkAway.includes('must') || walkAway.includes('critical')) { score -= 15; rationale.push('Customer must proceed'); }

  const inHouse = String(customerReq.in_house_capability || '').toLowerCase();
  if (inHouse === 'full' || inHouse.includes('strong')) { score += 10; rationale.push('Strong in-house capability'); }
  else if (inHouse === 'none' || inHouse.includes('no')) { score -= 10; rationale.push('No in-house alternative'); }
  else if (inHouse === 'partial') { score += 5; rationale.push('Partial in-house capability'); }

  const providerBATNA = parseInt(providerQuestionnaire.batna_quality) || 5;
  if (providerBATNA >= 8) { score -= 15; rationale.push('Provider has strong alternatives'); }
  else if (providerBATNA <= 3) { score += 15; rationale.push('Provider has limited alternatives'); }

  return { score: Math.max(20, Math.min(80, score)), rationale: rationale.join('. ') || 'Balanced alternatives' };
}

// Calculate all factors
const marketDynamics = calculateMarketDynamics();
const economicFactors = calculateEconomicFactors();
const strategicPosition = calculateStrategicPosition();
const batnaAnalysis = calculateBATNA();

console.log('Market Dynamics:', marketDynamics);
console.log('Economic Factors:', economicFactors);
console.log('Strategic Position:', strategicPosition);
console.log('BATNA Analysis:', batnaAnalysis);

// Overall leverage (weighted average)
const customerLeverage = Math.round(
  (marketDynamics.score * 0.25) +
  (economicFactors.score * 0.25) +
  (strategicPosition.score * 0.25) +
  (batnaAnalysis.score * 0.25)
);
const providerLeverage = 100 - customerLeverage;

console.log('=== FINAL LEVERAGE ===');
console.log('Customer:', customerLeverage + '%');
console.log('Provider:', providerLeverage + '%');
console.log('Data Source:', customerReq.data_source);

// Factors breakdown for storage
const leverageFactorsBreakdown = {
  marketDynamics: { score: marketDynamics.score, rationale: marketDynamics.rationale },
  economicFactors: { score: economicFactors.score, rationale: economicFactors.rationale },
  strategicPosition: { score: strategicPosition.score, rationale: strategicPosition.rationale },
  batna: { score: batnaAnalysis.score, rationale: batnaAnalysis.rationale },
  dataSource: customerReq.data_source || 'unknown'
};

return [{
  json: {
    sessionId,
    customerLeverage,
    providerLeverage,
    leverageFactorsBreakdown: JSON.stringify(leverageFactorsBreakdown),
    calculatedAt: new Date().toISOString(),
    dataSource: customerReq.data_source || 'unknown'
  }
}];

